window.BLUEFORCE_QUESTION_BANKS=window.BLUEFORCE_QUESTION_BANKS||{};window.BLUEFORCE_QUESTION_BANKS["ux-designer"]={"categoryOrder":["All","Discovery","UX Fundamentals","Human-Centered Design","Declarative Design","Testing","SLDS"],"questions":[{"id":1,"category":"Discovery","select":1,"question":"A sales team reports that creating an opportunity takes too long, but stakeholders cannot agree on where the problem occurs. What should the UX designer do first?","options":["Redesign the opportunity page immediately","Replace the standard Opportunity object with a custom object","Create a dashboard showing opportunity volume","Observe representative users completing the task and conduct contextual interviews"],"answers":[3],"explanation":"Direct observation and contextual interviews reveal the actual workflow, workarounds, interruptions, and environmental constraints. The complaint describes a symptom, not a verified cause. Redesigning before research risks optimizing the wrong step.","tip":"When the problem is vague, choose evidence-gathering before solution-building. Look for answers that let you see real behavior, not only stated preferences."},{"id":2,"category":"Discovery","select":1,"question":"What is the primary purpose of a heuristic evaluation?","options":["Have experts inspect an interface against established usability principles","Replace all end-user research","Calculate the financial return of a design","Measure production performance under heavy load"],"answers":[0],"explanation":"A heuristic evaluation is an expert review that identifies likely usability problems by comparing an interface with recognized principles. It is fast and useful, but it does not replace validation with real users.","tip":"Heuristic evaluation means expert inspection. Usability testing means representative users attempting realistic tasks."},{"id":3,"category":"Discovery","select":1,"question":"Users are abandoning a new case intake flow. Which activity best supports root-cause analysis before redesign?","options":["Copy the flow used by another company","Use the Five Whys with evidence from analytics, interviews, and observed failures","Ask stakeholders to vote on a new color palette","Add more required fields so the data is complete"],"answers":[1],"explanation":"Root-cause analysis repeatedly tests why the failure occurs and uses evidence to move beyond surface symptoms. Combining behavioral data with qualitative research reduces the chance of accepting a stakeholder assumption as the cause.","tip":"A strong root-cause answer connects a structured method with evidence. Avoid options that jump straight to a feature."},{"id":4,"category":"Discovery","select":1,"question":"A complex service process uses internal terminology that customers do not understand. What is the best content strategy?","options":["Keep the terminology because it matches the database field names","Use icons without text to reduce reading","Use plain language, consistent labels, and progressive disclosure for technical detail","Display every possible definition on the first screen"],"answers":[2],"explanation":"Content should support the user's mental model. Plain language and consistent labels reduce cognitive load, while progressive disclosure keeps advanced detail available without overwhelming the primary task.","tip":"Good content strategy prioritizes user comprehension over internal system vocabulary."},{"id":5,"category":"Discovery","select":1,"question":"Which information makes a persona most useful for Salesforce solution design?","options":["Only age, location, and department","A fictional name and stock photo only","The designer's assumptions about an average user","Job goals, behaviors, pain points, context, and evidence from research"],"answers":[3],"explanation":"A useful persona represents research-backed patterns that affect design decisions: goals, behaviors, environment, constraints, and pain points. Demographics alone rarely explain how someone works in Salesforce.","tip":"Personas are decision tools, not decorative profiles. Look for behavioral and task-based evidence."},{"id":6,"category":"Discovery","select":1,"question":"Before reorganizing a Lightning app's information architecture, what should the designer understand about the Salesforce data model?","options":["Objects, fields, relationships, record ownership, and how users move between related data","The JavaScript framework used by every component","Only the app's logo and brand colors","Only the number of licenses purchased"],"answers":[0],"explanation":"Information architecture must reflect how business information is structured and connected. Understanding objects and relationships helps the designer create navigation and page structures that match the user's work.","tip":"In Salesforce, UX and data architecture are closely linked. A navigation decision can expose or hide important record relationships."},{"id":7,"category":"UX Fundamentals","select":1,"question":"A service agent repeatedly switches between three pages to resolve one case. Which design principle should guide the redesign?","options":["Use a different font on each page","Require the agent to memorize record IDs","Reduce context switching by placing task-critical information and actions in the flow of work","Increase decorative imagery"],"answers":[2],"explanation":"Bringing related information and actions together reduces navigation cost, memory load, and error risk. The experience should support the user's end-to-end task rather than mirror organizational silos.","tip":"Follow the task, not the org chart. The best answer usually reduces steps, memory, and unnecessary movement."},{"id":8,"category":"UX Fundamentals","select":1,"question":"What does responsive design primarily accomplish?","options":["It creates a separate database for every device","It adapts layout and content presentation to different viewport sizes and capabilities","It guarantees identical pixel placement on every screen","It removes the need for mobile testing"],"answers":[1],"explanation":"Responsive design allows layouts to reorganize and scale for different screen sizes. It does not require identical presentation, and it still needs testing across devices and input methods.","tip":"Responsive does not mean identical. It means usable and appropriately adapted across contexts."},{"id":9,"category":"UX Fundamentals","select":1,"question":"When optimizing a Salesforce task for mobile, what should the designer prioritize?","options":["Hover-only interactions","Every desktop field and action on the first screen","Dense multi-column tables","The user's most important on-the-go tasks, touch-friendly controls, and progressive disclosure"],"answers":[3],"explanation":"Mobile design should focus on high-value tasks in the mobile context, reduce visual density, and support touch. Less frequent details can remain available through progressive disclosure.","tip":"Ask what the user must accomplish while mobile, not how to shrink the desktop page."},{"id":10,"category":"UX Fundamentals","select":1,"question":"A status is shown only by red or green text. What is the most accessible improvement?","options":["Make the text smaller","Add a text label or icon with an accessible name in addition to color","Use brighter red and green","Remove the status entirely"],"answers":[1],"explanation":"Color should not be the only way to communicate meaning. A text label or appropriately labeled icon allows users with color-vision differences and assistive technology to understand the status.","tip":"Whenever an option says 'color alone,' treat it as an accessibility warning."},{"id":11,"category":"UX Fundamentals","select":1,"question":"Which combination most directly creates clear visual hierarchy on a record page?","options":["Meaningful grouping, spacing, alignment, size, and contrast","All content displayed at the same visual weight","Random font styles and equal spacing","More borders around every field"],"answers":[0],"explanation":"Visual hierarchy uses grouping and differences in emphasis to communicate order and importance. When everything has equal weight, users must work harder to decide where to look and what to do.","tip":"Hierarchy is about relationships and priority, not decoration."},{"id":12,"category":"UX Fundamentals","select":1,"question":"A company's brand color does not provide sufficient contrast for body text. What should the designer do?","options":["Reduce the font weight","Use it anyway because branding overrides accessibility","Choose an accessible brand-approved variation or reserve the color for non-text accents","Place the text over a patterned image"],"answers":[2],"explanation":"Brand expression must operate within accessibility requirements. Designers can use an accessible tonal variation, adjust the background, or apply the color to decorative elements rather than essential text.","tip":"Accessibility is a design constraint, not an optional layer added after branding."},{"id":13,"category":"UX Fundamentals","select":1,"question":"During early concept exploration, why is a low-fidelity prototype often preferable?","options":["It accurately measures production load time","It eliminates the need for later testing","It enables fast, inexpensive feedback before the team becomes attached to visual details","It proves the solution is technically complete"],"answers":[2],"explanation":"Low-fidelity prototypes make structure and flow easy to change. Participants and stakeholders are also more likely to critique the concept instead of focusing on polished colors and typography.","tip":"Match prototype fidelity to the question you need to answer. Early uncertainty usually calls for lower fidelity."},{"id":14,"category":"UX Fundamentals","select":1,"question":"What is the best way to present a validation error in a multi-field form?","options":["Wait until the user leaves the application","Provide a clear summary and place specific, actionable messages next to the affected fields","Clear all entered data","Show a red border with no text"],"answers":[1],"explanation":"Accessible error handling identifies what went wrong, where it happened, and how to correct it. Inline messages reduce search effort, while a summary helps users understand the overall state.","tip":"A good error message is perceivable, specific, and actionable."},{"id":15,"category":"Human-Centered Design","select":1,"question":"Which artifact best visualizes a user's stages, actions, thoughts, emotions, pain points, and opportunities across an end-to-end experience?","options":["Journey map","Permission set matrix","Release calendar","Entity-relationship diagram"],"answers":[0],"explanation":"A journey map shows the experience over time from the user's perspective. It helps teams identify emotional highs and lows, gaps between touchpoints, and moments where design can improve the relationship.","tip":"Journey map equals the user's experience over time. Service blueprint adds operational layers behind that experience."},{"id":16,"category":"Human-Centered Design","select":1,"question":"What does a service blueprint add beyond a basic customer journey map?","options":["Only database storage limits","Only brand colors","A list of Salesforce certification vouchers","Frontstage interactions, backstage activities, supporting processes, and dependencies"],"answers":[3],"explanation":"A service blueprint connects the visible customer experience to the people, processes, systems, and policies that make it possible. It is especially useful when failures span multiple teams or channels.","tip":"Think 'journey plus operations.'"},{"id":17,"category":"Human-Centered Design","select":1,"question":"Which approach best demonstrates inclusive design?","options":["Treat accessibility as a compliance review after development","Design for an imagined average user and test at launch","Include people with diverse abilities and contexts throughout research, design, and testing","Create one solution only for permanent visual disabilities"],"answers":[2],"explanation":"Inclusive design involves diverse participants early and repeatedly. It considers permanent, temporary, and situational barriers instead of assuming one 'average' user represents everyone.","tip":"Inclusive design is a continuous practice, not a final checklist."},{"id":18,"category":"Human-Centered Design","select":1,"question":"Which set contains the four Salesforce Relationship Design mindsets?","options":["Discover, define, develop, deliver","Compassion, courage, intention, reciprocity","Research, code, launch, maintain","Speed, scale, profit, control"],"answers":[1],"explanation":"Salesforce describes the Relationship Design mindsets as compassion, courage, intention, and reciprocity. Together they encourage meaningful, ethical, and lasting value exchange among people, organizations, and communities.","tip":"Remember the mindsets as human qualities that strengthen long-term relationships, not project phases."},{"id":19,"category":"Human-Centered Design","select":1,"question":"A proposed feature is desirable to users and technically feasible, but it has no sustainable business model. Which human-centered design criterion is missing?","options":["Viability","Findability","Fidelity","Legibility"],"answers":[0],"explanation":"Human-centered design seeks the intersection of desirability, feasibility, and viability. Viability asks whether the solution can work sustainably for the organization or business model.","tip":"Desirable = people need it. Feasible = it can be built. Viable = the organization can sustain it."},{"id":20,"category":"Human-Centered Design","select":1,"question":"What is the strongest way to apply reciprocity during solution design?","options":["Hide design constraints from stakeholders","Collect user feedback once and never follow up","Prioritize company value while ignoring user outcomes","Co-create with users, return value, and keep the feedback relationship active over time"],"answers":[3],"explanation":"Reciprocity recognizes that relationships require two-way value exchange. Co-creation and ongoing feedback help the organization remain relevant while giving participants meaningful influence and benefit.","tip":"Reciprocity is not one-way data collection; it is continuing exchange and shared value."},{"id":21,"category":"Declarative Design","select":1,"question":"A company needs to track organizations it sells to. The standard Account object already supports the required process. What is the best design choice?","options":["Create a separate Salesforce org for every customer","Use and configure the standard Account object","Store each organization in a text field on User","Create a custom Company object to make the org unique"],"answers":[1],"explanation":"Use standard objects when they fit the business concept. Standard objects integrate naturally with platform features, reporting, relationships, and future Salesforce capabilities, reducing maintenance and user confusion.","tip":"Prefer native capabilities unless a verified requirement cannot be met. Custom does not automatically mean better UX."},{"id":22,"category":"Declarative Design","select":1,"question":"A child record must always belong to a parent, inherit ownership and sharing, and support roll-up summary fields on the parent. Which relationship is most appropriate?","options":["Unrelated text field","Many-to-many relationship without a junction object","Master-detail relationship","External lookup"],"answers":[2],"explanation":"A master-detail relationship tightly couples the child to the parent, supports inherited ownership and sharing, and enables roll-up summary fields. A lookup relationship is looser and does not provide all of these behaviors.","tip":"Master-detail means strong dependency. Lookup means a more independent relationship."},{"id":23,"category":"Declarative Design","select":1,"question":"A designer needs to change which fields and actions appear for different users, while another requirement changes the component arrangement on the Lightning page. Which tools are most relevant?","options":["Email templates and dashboards","Only Data Loader","Only Schema Builder","Page layouts for fields/actions and Lightning App Builder for page components"],"answers":[3],"explanation":"Page layouts influence record details and available actions, often by profile or record type. Lightning App Builder controls the structure and components of Lightning pages. The two tools solve related but different presentation needs.","tip":"Page layout = record fields and actions. Lightning App Builder = the page canvas and components."},{"id":24,"category":"Declarative Design","select":1,"question":"What is a primary UX advantage of Dynamic Forms?","options":["They let admins place fields and field sections as components and apply visibility rules","They replace object permissions","They automatically migrate every custom component to mobile","They remove the need for a data model"],"answers":[0],"explanation":"Dynamic Forms provide more granular control over field placement and visibility on supported Lightning record pages. This supports progressive disclosure and role- or record-specific experiences without creating many page layouts.","tip":"Dynamic Forms improve presentation logic; they do not replace security."},{"id":25,"category":"Declarative Design","select":1,"question":"A sales manager wants representatives to see deal stages, important fields, and stage-specific coaching. Which Salesforce feature best fits?","options":["Recycle Bin","Path with key fields and Guidance for Success","Chatter feed tracking only","A static image uploaded to Files"],"answers":[1],"explanation":"Path visually represents stages and can show key fields plus Guidance for Success at each stage. It supports process clarity and just-in-time coaching in the context of the record.","tip":"When the scenario mentions stages plus coaching, think Path."},{"id":26,"category":"Declarative Design","select":1,"question":"Users need quick access to Notes and History while working anywhere inside a Lightning app. What should the designer configure?","options":["A validation rule","A different home page for each record","A utility bar","A new custom object for every note"],"answers":[2],"explanation":"The utility bar provides persistent access to common productivity tools in a fixed footer. Utilities open in docked panels so users can maintain context while working in the app.","tip":"Persistent, app-level productivity tools point to the utility bar."},{"id":27,"category":"Declarative Design","select":1,"question":"Which statement correctly distinguishes App Manager from Lightning App Builder?","options":["Lightning App Builder manages licenses; App Manager writes Apex","They are identical tools with different names","App Manager creates only reports; Lightning App Builder creates users","App Manager configures apps, navigation, and branding; Lightning App Builder creates and arranges Lightning pages"],"answers":[3],"explanation":"App Manager is used to create and configure Lightning apps, including branding and navigation. Lightning App Builder is the visual tool for composing app pages, home pages, and record pages from components.","tip":"App Manager defines the container and navigation. App Builder defines the pages inside the experience."},{"id":28,"category":"Declarative Design","select":1,"question":"An executive needs a visual summary of pipeline metrics sourced from several reports. What is the most appropriate declarative feature?","options":["Dashboard","Page layout","Permission set","Path"],"answers":[0],"explanation":"Dashboards present visual components based on source reports. They are appropriate when users need at-a-glance monitoring and comparisons rather than row-level data entry.","tip":"Reports organize and analyze data; dashboards visualize report results."},{"id":29,"category":"Declarative Design","select":1,"question":"A new feature requires a hands-on, multi-step tour that points users through a sequence of actions. Which in-app guidance component is best?","options":["Dashboard filter","Walkthrough","Compact layout","Field-level help"],"answers":[1],"explanation":"A walkthrough is an interactive sequence designed to guide users through onboarding or feature adoption steps. A prompt is better for a focused message, while field-level help explains an individual field.","tip":"Sequence of guided steps = walkthrough. One contextual message = prompt."},{"id":30,"category":"Declarative Design","select":1,"question":"A product team wants to announce a new feature on the exact page where users can try it. Which declarative engagement component is the best starting point?","options":["A master-detail relationship","A sharing rule","An outbound message","A targeted prompt"],"answers":[3],"explanation":"A targeted prompt can call attention to a relevant feature or action in context. It is well suited to feature discovery, announcements, and just-in-time guidance on a specific page.","tip":"When the message should appear in context and drive one action, choose a prompt."},{"id":31,"category":"Declarative Design","select":1,"question":"Users repeatedly misunderstand what a custom field means. The explanation is short and specific to that field. What is the simplest appropriate solution?","options":["A five-step walkthrough","A new dashboard","Field-level help","A custom mobile app"],"answers":[2],"explanation":"Field-level help explains the purpose and function of a standard or custom field at the point of use. It avoids forcing users to leave their workflow to search for documentation.","tip":"Use the smallest guidance mechanism that solves the problem."},{"id":32,"category":"Declarative Design","select":1,"question":"A user should be able to create a new task from many places in Salesforce without navigating to a specific record first. Which feature is most appropriate?","options":["Global action","Related list filter","Record type","Report chart"],"answers":[0],"explanation":"Global actions are available in broadly accessible interface locations and support actions that are not dependent on a particular record context. They reduce navigation for common cross-app tasks.","tip":"Record-specific action needs a record context. Global action is designed for broad access."},{"id":33,"category":"Declarative Design","select":1,"question":"A company wants its Lightning experience to use approved logos, colors, and page background styling without custom code. What should the designer evaluate first?","options":["Themes and Branding","Apex triggers","Duplicate rules","Data export"],"answers":[0],"explanation":"Themes and Branding provides declarative control over core visual identity elements in Lightning Experience. It is the native starting point before considering more expensive custom development.","tip":"For global, declarative brand expression, start with Themes and Branding."},{"id":34,"category":"Testing","select":1,"question":"Which usability-test task is written most effectively?","options":["Explore the application and do anything you like","Click the blue New Contact button and complete the form","Tell us why our design is easy to use","You have just met a new customer. Add their contact information so your team can follow up"],"answers":[3],"explanation":"A good task describes a realistic goal without revealing the interface steps or preferred answer. This lets the designer observe whether users can discover and complete the task naturally.","tip":"Task scenarios describe intent, not clicks. Avoid leading users through the interface."},{"id":35,"category":"Testing","select":1,"question":"When is A/B testing most appropriate?","options":["When the team has no hypothesis or metric","When testing a completely nonfunctional sketch for technical performance","When comparing two defined design variants against a measurable outcome","When interviewing one stakeholder about strategy"],"answers":[2],"explanation":"A/B testing compares variants under controlled conditions and measures a target behavior or outcome. It works best when the team has a clear hypothesis, enough traffic or participants, and a meaningful metric.","tip":"A/B testing answers 'which variant performs better on this metric?' It does not explain every reason why."},{"id":36,"category":"Testing","select":1,"question":"A designer wants to validate whether users can find topics in a proposed navigation hierarchy before visual design is complete. Which method is best?","options":["Color-contrast audit","Tree testing","Load testing","Code review"],"answers":[1],"explanation":"Tree testing evaluates findability within a text-based hierarchy, separating information architecture from visual presentation. It helps identify confusing labels and misplaced content early.","tip":"Card sorting helps create categories; tree testing evaluates whether users can find items in the resulting hierarchy."},{"id":37,"category":"Testing","select":1,"question":"Why establish a usability benchmark before redesigning a high-volume task?","options":["To compare measures such as completion rate, time, errors, and satisfaction before and after changes","To select brand colors","To guarantee every user will like the new design","To avoid speaking with users"],"answers":[0],"explanation":"A benchmark provides a baseline for evaluating whether the redesign improved measurable outcomes. It turns 'the new experience feels better' into evidence that can support decisions.","tip":"A benchmark is a before-state measurement used for comparison."},{"id":38,"category":"Testing","select":1,"question":"A researcher believes a new flow is better and asks only questions that support that belief. Which risk is most evident?","options":["Responsive design","Progressive disclosure","Data normalization","Confirmation bias"],"answers":[3],"explanation":"Confirmation bias leads people to seek or interpret evidence that supports an existing belief. Neutral questions, predefined success criteria, diverse participants, and review by others can reduce this risk.","tip":"Watch for wording that reveals the researcher's preferred answer."},{"id":39,"category":"SLDS","select":1,"question":"What is the primary value of Salesforce Lightning Design System?","options":["It is only a library of company logos","It automatically writes every business requirement","It provides reusable patterns, components, guidance, and design foundations for consistent Salesforce experiences","It replaces the Salesforce data model"],"answers":[2],"explanation":"SLDS helps teams create experiences that are consistent with Salesforce through shared patterns, components, visual foundations, and guidance. Reuse improves quality, accessibility, and delivery efficiency.","tip":"A design system is more than a component library; it also includes standards, principles, and documentation."},{"id":40,"category":"SLDS","select":1,"question":"A standard Lightning base component already meets the functional requirement. What should the team generally do?","options":["Rebuild it from scratch for uniqueness","Use the base component and its supported configuration","Copy its internal rendered HTML and override every class","Replace it with an image"],"answers":[1],"explanation":"Base components provide supported behavior, accessibility, interaction patterns, and alignment with Salesforce. Rebuilding a standard component creates unnecessary maintenance and can introduce accessibility defects.","tip":"Prefer supported platform components before custom code."},{"id":41,"category":"SLDS","select":1,"question":"Which statement best describes a design token?","options":["A user authentication credential","A test script for a flow","A database record ID","A named entity that stores a visual design value such as color, spacing, or typography"],"answers":[3],"explanation":"Design tokens store named visual attributes so design decisions can be reused consistently. Current Salesforce guidance favors global styling hooks where possible for cross-version theming, especially when preparing for SLDS 2.","tip":"Token = named design value. Styling hook = CSS custom property used to customize supported styling."},{"id":42,"category":"SLDS","select":1,"question":"A team wants component styling to remain compatible across SLDS 1 and SLDS 2. Which current approach is generally preferred?","options":["Use supported global styling hooks where possible","Override internal classes of base components","Hardcode colors in every component","Depend only on legacy design tokens"],"answers":[0],"explanation":"Salesforce recommends global styling hooks as the more future-compatible approach. Legacy design tokens are associated with SLDS 1 themes and are not supported in SLDS 2 themes.","tip":"For current platform compatibility, think supported hooks, not internal overrides or hardcoded values."},{"id":43,"category":"SLDS","select":1,"question":"What is the main purpose of the SLDS grid system?","options":["Define user permissions","Create responsive page layouts using a consistent column and sizing structure","Encrypt Salesforce records","Schedule reports"],"answers":[1],"explanation":"The grid system supports responsive, structured layouts using predictable sizing and alignment. It helps content reflow across screen sizes while maintaining consistent spacing and proportions.","tip":"Grid questions are usually about responsive layout, alignment, and structure."},{"id":44,"category":"SLDS","select":1,"question":"A utility icon communicates an important action. What additional accessibility support is required?","options":["Rely on the icon shape alone","Use the same icon for unrelated actions","Provide a clear accessible name or assistive text and an adequate target size","Make it visible only on hover"],"answers":[2],"explanation":"Icons must have a programmatically available name when they communicate meaning or trigger an action. Adequate target size and consistent use also improve operability and comprehension.","tip":"An icon's visual meaning is not automatically available to a screen reader."},{"id":45,"category":"SLDS","select":1,"question":"Which treatment best supports keyboard users?","options":["Remove focus outlines for a cleaner appearance","Require a mouse for all controls","Move focus unpredictably after every click","Provide a visible focus indicator and a logical focus order"],"answers":[3],"explanation":"Keyboard users need to know which element is active and move through controls in a meaningful sequence. Focus should remain visible and should only move programmatically when the interaction clearly requires it.","tip":"Never trade away visible focus for aesthetics."},{"id":46,"category":"SLDS","select":1,"question":"What does an SLDS component blueprint primarily provide?","options":["Recommended markup structure, classes, variants, states, and usage guidance","A finished business process with organization-specific logic","A replacement for user research","A Salesforce license"],"answers":[0],"explanation":"A blueprint documents the structure and styling conventions for a component pattern. Teams still need to implement behavior, data, accessibility details, and business logic appropriate to their context.","tip":"Blueprints guide implementation; they are not complete applications."},{"id":47,"category":"SLDS","select":1,"question":"A developer wants to restyle a Lightning base component by targeting its internal rendered classes. What is the best guidance?","options":["Modify Salesforce's source code","Avoid internal class overrides; use documented variants, utility classes, or supported styling hooks","Do it because internal markup never changes","Use an exact class-string selector"],"answers":[1],"explanation":"Internal markup and classes of base components are implementation details and can change. Salesforce identifies direct SLDS class overrides and dependence on rendered markup as styling anti-patterns.","tip":"Supported extension points are stable; internal implementation details are not."},{"id":48,"category":"SLDS","select":1,"question":"A custom interface uses a different icon style, spacing scale, and button behavior on every page. Which design-system action provides the greatest long-term value?","options":["Continue adding one-off exceptions","Hide the inconsistencies with animation","Standardize reusable patterns and components, document decisions, and govern contributions","Create more unrelated color palettes"],"answers":[2],"explanation":"A design system creates value through reuse and governance. Standard patterns reduce cognitive load for users and duplicated effort for teams, while documentation and contribution rules help the system remain coherent over time.","tip":"The long-term answer is usually systematic reuse and governance, not another isolated fix."},{"id":49,"category":"Discovery","select":1,"question":"Interviews reveal several possible usability problems, but the team needs to understand how common each problem is across 2,000 users. What should the designer do next?","options":["Build every requested feature","Replace interviews with a brand workshop","Choose the problem mentioned by the most senior stakeholder","Run a structured survey with a representative sample"],"answers":[3],"explanation":"Interviews are strong for discovering themes and understanding why problems occur. A structured survey can then quantify how widespread those themes are across a larger representative population.","tip":"Use qualitative research to discover and explain; use quantitative research to measure prevalence or magnitude."},{"id":50,"category":"Discovery","select":1,"question":"Sales, service, and compliance stakeholders disagree about the goals of a new onboarding experience. Which artifact should the designer create first to clarify influence, needs, and decision ownership?","options":["A component blueprint","A stakeholder map","A production dashboard","A color-contrast matrix"],"answers":[1],"explanation":"A stakeholder map identifies who is affected, who has influence, what each group needs, and where decision authority sits. This makes conflicts visible before the team commits to a solution.","tip":"When the challenge is alignment among people, choose a stakeholder or decision-mapping activity before interface design."},{"id":51,"category":"Discovery","select":1,"question":"Analytics show that users abandon a flow on step three. What additional research would best explain why they leave?","options":["Observe users attempting the flow and ask neutral follow-up questions","Increase the sample size of the same analytics report only","Change the company logo","Remove step three without investigation"],"answers":[0],"explanation":"Analytics reveal where behavior occurs, but direct observation and neutral interviews help explain the motivations, confusion, missing information, or environmental constraints behind that behavior.","tip":"Behavioral data often tells you what and where; qualitative research helps reveal why."},{"id":52,"category":"Discovery","select":1,"question":"A help center contains duplicate, outdated, and inconsistently labeled articles. Which discovery activity should precede a new content structure?","options":["Convert every article into a video","Rename database objects","Perform a content inventory and audit","Add more navigation levels immediately"],"answers":[2],"explanation":"A content inventory documents what exists, while an audit evaluates accuracy, duplication, ownership, usefulness, and gaps. The findings provide evidence for consolidation and a clearer information architecture.","tip":"Before reorganizing content, understand the current content set and its quality."},{"id":53,"category":"Discovery","select":1,"question":"A designer is planning an experience that shows accounts, contacts, cases, and assets together. What should be clarified during discovery?","options":["The maximum number of animations per page","The designer's personal navigation habits","The relationships among the objects and which records users need in each task","Only the preferred button color"],"answers":[2],"explanation":"Salesforce experiences depend on the underlying data model. Understanding object relationships and task-specific information needs helps the designer present connected data without creating misleading or redundant structures.","tip":"When a scenario names several Salesforce records, examine data relationships before choosing the page structure."},{"id":54,"category":"Discovery","select":1,"question":"Which interview question is least likely to lead a participant?","options":["Wouldn't a guided wizard make this easier?","Tell me about the last time you created a case","Do you agree that the current page is confusing?","Which of our two proposed solutions do you prefer?"],"answers":[1],"explanation":"Asking about a recent real experience encourages concrete evidence without implying a preferred answer. The other questions introduce assumptions or constrain the participant to solutions chosen by the team.","tip":"Ask about past behavior and specific examples rather than asking users to confirm your idea."},{"id":55,"category":"Discovery","select":1,"question":"Research participants describe a slow approval process, but observation shows that most delay occurs while they search for missing information. What should the problem statement emphasize?","options":["The evidence-based information-finding barrier","A predetermined need for custom code","The participants' first explanation without qualification","The number of stakeholders in the meeting"],"answers":[0],"explanation":"A useful problem statement reflects the validated user need and context. Observation has identified a more specific barrier than the initial description, so the team should frame the problem around finding required information.","tip":"Separate the user's reported symptom from the root cause supported by evidence."},{"id":56,"category":"UX Fundamentals","select":1,"question":"A record page contains many elements with equal visual emphasis. Users struggle to identify what to do first. What should the designer improve?","options":["The user's profile permissions","The database storage limit","The number of decorative icons","Visual hierarchy using size, position, spacing, and emphasis"],"answers":[3],"explanation":"Visual hierarchy guides attention by making primary information and actions more prominent than supporting content. Size, placement, grouping, spacing, and contrast should communicate importance consistently.","tip":"When users cannot tell what matters first, think hierarchy rather than adding more content."},{"id":57,"category":"UX Fundamentals","select":1,"question":"A status is communicated only by changing a field from green to red. What is the main accessibility problem?","options":["The colors are part of the corporate brand","The status uses too few database fields","Color is being used as the only cue","The page contains no animation"],"answers":[2],"explanation":"Users with color-vision differences or nonvisual access may not perceive the change. Add text, an icon with an accessible name, or another redundant cue while maintaining sufficient contrast.","tip":"Never rely on color alone to communicate meaning, state, or required action."},{"id":58,"category":"UX Fundamentals","select":1,"question":"A form shows validation errors only after submission and lists them at the top without identifying the fields. What improvement best supports recovery?","options":["Clear the entire form after each error","Place clear error messages near the affected fields and preserve entered data","Hide required-field indicators","Use a generic message that says Invalid"],"answers":[1],"explanation":"Specific, field-level feedback helps users locate and correct problems efficiently. Preserving their input prevents unnecessary rework and frustration.","tip":"Good error handling explains what happened, where it happened, and how to fix it."},{"id":59,"category":"UX Fundamentals","select":1,"question":"Which design best follows recognition rather than recall?","options":["Show recently used records and clearly labeled choices","Hide actions until users enter an undocumented command","Require users to remember record IDs","Use unlabeled icons for every task"],"answers":[0],"explanation":"Recognition reduces memory demand by making relevant choices and context visible. Requiring users to remember identifiers or hidden commands increases cognitive load and error risk.","tip":"Prefer visible choices, examples, defaults, and context over memorization."},{"id":60,"category":"UX Fundamentals","select":1,"question":"A desktop experience reveals important instructions only when the pointer hovers over an icon. Why is this unsuitable for a mobile-first design?","options":["Salesforce Mobile supports only text fields","Mobile devices cannot display icons","Responsive pages cannot include instructions","Touch devices do not provide a reliable hover interaction"],"answers":[3],"explanation":"Hover is not consistently available on touch devices and may also be inaccessible to keyboard users. Important information should be discoverable through visible text or an operable control.","tip":"Do not make critical content depend on hover. Design for touch, keyboard, and assistive technology."},{"id":61,"category":"UX Fundamentals","select":1,"question":"A user clicks Save, but the interface appears unchanged for several seconds. Which UX principle is missing?","options":["Stakeholder mapping","Data normalization","Timely system feedback","Brand differentiation"],"answers":[2],"explanation":"The interface should acknowledge the action with a loading state, disabled control, progress indicator, or confirmation. Feedback reassures users that the system received the request and helps prevent duplicate actions.","tip":"Every meaningful user action should produce a clear and timely response from the system."},{"id":62,"category":"UX Fundamentals","select":1,"question":"Marketing requests a highly branded Salesforce experience. Which approach best balances brand identity and usability?","options":["Use brand colors regardless of contrast","Replace every standard control with an unfamiliar custom interaction","Remove labels so the interface looks minimal","Apply brand elements consistently while preserving familiar interaction patterns, readability, and accessibility"],"answers":[3],"explanation":"Brand expression should reinforce trust and identity without making common tasks harder. Familiar patterns, sufficient contrast, clear labels, and consistency remain more important than visual novelty.","tip":"Branding should support the experience, not override established usability and accessibility needs."},{"id":63,"category":"UX Fundamentals","select":1,"question":"A page displays 30 fields in one uninterrupted column. Which change most directly improves scanning?","options":["Add a different background color to every field","Group related fields under clear headings and reveal secondary information progressively","Remove all whitespace","Repeat the same field in multiple sections"],"answers":[1],"explanation":"Chunking related information and using progressive disclosure creates meaningful structure, reduces perceived complexity, and helps users locate the fields relevant to their current task.","tip":"To reduce cognitive load, group, prioritize, and progressively disclose rather than merely shrinking content."},{"id":64,"category":"Human-Centered Design","select":1,"question":"What should a journey map normally show in addition to process steps?","options":["User goals, touchpoints, emotions, pain points, and opportunities over time","Only the final screen layout","Only the Salesforce object API names","A list of developers assigned to the project"],"answers":[0],"explanation":"A journey map visualizes the experience across time, including what users try to accomplish, where interactions occur, how they feel, and where the organization can improve the experience.","tip":"Journey maps connect stages with the human experience, not just an internal workflow."},{"id":65,"category":"Human-Centered Design","select":1,"question":"A team needs to understand how customer-facing support interactions depend on agents, policies, and backend systems. Which artifact is most appropriate?","options":["A typography scale","A service blueprint","A mood board","A database backup"],"answers":[1],"explanation":"A service blueprint connects customer actions and frontstage interactions with backstage people, processes, systems, and support activities. It exposes operational dependencies behind the experience.","tip":"Journey map focuses on the user's experience; service blueprint adds the organizational machinery that delivers it."},{"id":66,"category":"Human-Centered Design","select":1,"question":"Which action best reflects relationship design?","options":["Hide how customer data will be used","Treat every interaction as an isolated screen","Design interactions that build trust, reciprocity, transparency, and long-term value for all participants","Maximize clicks regardless of user outcomes"],"answers":[2],"explanation":"Relationship design considers the quality and sustainability of relationships among people, organizations, communities, and systems. Trust and mutual value are central outcomes.","tip":"Look beyond task completion to the long-term relationship created by the experience."},{"id":67,"category":"Human-Centered Design","select":1,"question":"A research plan includes only experienced desktop users even though the product serves new mobile users and people using assistive technology. What should the designer do?","options":["Continue because expert users are faster to recruit","Ask stakeholders to imagine the excluded users","Remove accessibility requirements","Recruit participants that represent the full range of relevant contexts and abilities"],"answers":[3],"explanation":"Inclusive design requires involving people whose abilities, environments, devices, and experience levels reflect the real audience. Excluding them creates blind spots that can become systemic barriers.","tip":"Design with excluded or underserved users, not only for an imagined average user."},{"id":68,"category":"Human-Centered Design","select":1,"question":"During prototyping, users repeatedly misunderstand the same interaction. What is the most human-centered response?","options":["Revisit the assumptions, revise the prototype, and test again","Ask only the project sponsor to approve it","Train users to accept the original design","Ignore the finding because development has not started"],"answers":[0],"explanation":"Human-centered design is iterative. Repeated misunderstanding is evidence that the concept or interaction needs revision, followed by another round of validation.","tip":"Testing is not a final gate; it feeds the next design iteration."},{"id":69,"category":"Human-Centered Design","select":1,"question":"A consent dialog makes Accept prominent and hides Decline behind several steps. Which ethical concern is most relevant?","options":["The data model needs a master-detail relationship","The design manipulates choice through a dark pattern","The interface uses progressive disclosure correctly","The experience has too much whitespace"],"answers":[1],"explanation":"A dark pattern steers users toward an outcome that may not align with their interests or informed choice. Ethical design presents meaningful options transparently and with comparable clarity.","tip":"A choice is not truly informed when the interface intentionally makes one option difficult to find or select."},{"id":70,"category":"Declarative Design","select":1,"question":"A company needs to track a new business entity that does not fit Accounts, Contacts, Opportunities, Cases, or another standard object. What is the most appropriate declarative approach?","options":["Rename an unrelated standard object","Store every value in a single text field","Create a dashboard without storing records","Create a custom object with the required fields and relationships"],"answers":[3],"explanation":"A custom object is appropriate when a distinct business entity needs its own records, fields, relationships, security, and user experience. Standard objects should be used when their purpose matches the requirement.","tip":"Use standard objects for their intended business concepts; use a custom object for a genuinely new entity."},{"id":71,"category":"Declarative Design","select":1,"question":"Two sales processes need different opportunity stages, page layouts, and picklist values. Which configuration best supports this?","options":["A single page layout for every user","A utility bar item","Record types combined with sales processes and assigned page layouts","A dashboard filter"],"answers":[2],"explanation":"Record types can present different business processes, picklist values, and page layouts to different groups. This supports meaningful variation without creating separate objects.","tip":"When the same object needs different processes and presentations, think record types plus layouts."},{"id":72,"category":"Declarative Design","select":1,"question":"A field should appear on an opportunity record only when the deal type is Partner. Which feature should the designer recommend?","options":["Dynamic Forms field visibility rules","A custom login page","A separate dashboard","A new standard object"],"answers":[0],"explanation":"Dynamic Forms can place fields and sections as individual components and control their visibility based on record data, user attributes, or other supported criteria.","tip":"Use Dynamic Forms when the requirement is conditional field or section visibility on supported record pages."},{"id":73,"category":"Declarative Design","select":1,"question":"Users need an object-specific workspace that changes according to the record they are viewing. What should be configured in Lightning App Builder?","options":["A Lightning record page","A global value set","A report folder","A login flow"],"answers":[0],"explanation":"A Lightning record page defines the component-based experience for a specific object record. It can be assigned by app, record type, and profile as supported.","tip":"Record page = one record's workspace; app page = standalone custom page; home page = Lightning home experience."},{"id":74,"category":"Declarative Design","select":1,"question":"Sales representatives need stage-specific guidance and key fields while moving opportunities through a defined process. Which feature is best?","options":["A custom tab containing a static image","A joined report","Themes and Branding","Path"],"answers":[3],"explanation":"Path highlights the current stage, key fields, and guidance for success. It supports users through a sequence tied to a picklist such as Opportunity Stage.","tip":"When the requirement mentions stages, key fields, and guidance, Path is a strong candidate."},{"id":75,"category":"Declarative Design","select":1,"question":"Service agents need constant access to notes and history while moving between records in a Lightning app. Which global app feature can reduce navigation?","options":["Record type","Compact layout","Utility bar","Validation rule"],"answers":[2],"explanation":"The utility bar gives users persistent access to productivity tools within a Lightning app, reducing the need to leave their current context.","tip":"Utility bar items are persistent app-level tools, not record-specific page sections."},{"id":76,"category":"Declarative Design","select":1,"question":"A new feature is available to a small group of users, and the team wants a contextual message pointing to the feature the first time they encounter it. What should the designer consider?","options":["A new custom object","A targeted in-app guidance prompt","A public dashboard","A duplicate rule"],"answers":[1],"explanation":"In-app guidance can deliver contextual prompts or walkthroughs to targeted users at relevant locations. It is suited to onboarding, feature discovery, and adoption support.","tip":"Choose in-app guidance when users need contextual learning inside the product."},{"id":77,"category":"Declarative Design","select":1,"question":"Executives need a visual summary of pipeline value, win rate, and performance trends. Which declarative solution is most appropriate?","options":["Reports feeding dashboard components","A page layout with every opportunity field","A utility icon","A custom object with no records"],"answers":[0],"explanation":"Reports organize and aggregate record data, while dashboards present selected metrics visually. Together they support monitoring and decision-making without requiring users to inspect individual records.","tip":"Reports answer detailed data questions; dashboards surface key metrics and trends at a glance."},{"id":78,"category":"Declarative Design","select":1,"question":"Which configuration controls the fields shown in a record's highlights panel in Lightning Experience?","options":["The utility bar","The report type","The app's navigation style","The compact layout assigned to the record type"],"answers":[3],"explanation":"The highlights panel uses the primary compact layout to display key record fields. Selecting concise, decision-relevant fields improves scanning.","tip":"Page layout controls broader record detail; compact layout supplies key fields for the highlights panel and mobile record header."},{"id":79,"category":"Declarative Design","select":1,"question":"Users need to create the same type of related record from several places in Salesforce. Which feature provides a broadly accessible creation action?","options":["A theme","A global action","A record type description","A field history report"],"answers":[1],"explanation":"Global actions can be available from multiple locations and can create records or perform other supported actions without requiring users to begin on a specific parent record.","tip":"Global actions are broadly accessible; object-specific actions depend on the current record context."},{"id":80,"category":"Declarative Design","select":1,"question":"A sales manager wants representatives to view opportunities grouped by stage and move records between stages visually. Which standard feature best fits?","options":["A static HTML page","Themes and Branding","Kanban view for an appropriate list view","A compact layout"],"answers":[2],"explanation":"Kanban provides a visual representation of records grouped by a selected field and can support moving records between columns when the configuration and permissions allow it.","tip":"Kanban is useful for visually managing records across stages or statuses."},{"id":81,"category":"Declarative Design","select":1,"question":"Agents need a preconfigured action on the Case record that opens a short form with only the fields required to escalate the case. What should be used?","options":["A new home page","A navigation menu label","A dashboard subscription","An object-specific quick action"],"answers":[3],"explanation":"An object-specific quick action can provide a focused form and maintain the context of the current record. Limiting the action layout to necessary fields makes the task faster and clearer.","tip":"Quick actions support focused, contextual tasks without exposing the entire record edit experience."},{"id":82,"category":"Declarative Design","select":1,"question":"A record page is cluttered because several long related lists push critical information far below the fold. What is the best declarative redesign?","options":["Prioritize key related data and organize secondary content with tabs, accordions, or appropriate related-list components","Remove all section labels","Add every available related list","Use a different font for each relationship"],"answers":[0],"explanation":"Component-based organization and prioritization reduce scrolling while preserving access to supporting information. The page should reflect task importance rather than display every relationship equally.","tip":"Use tabs and progressive disclosure to manage secondary record information, but keep critical content visible."},{"id":83,"category":"Declarative Design","select":1,"question":"A process requires users to complete several guided screens, make decisions, and create records without custom code. Which tool is most appropriate?","options":["A compact layout","A Screen Flow","A theme","A static dashboard"],"answers":[1],"explanation":"Screen Flows can guide users through multi-step interactions, collect input, apply logic, and perform data actions declaratively. They are suitable when a focused wizard improves task completion.","tip":"When users need a guided multi-step process with logic and data updates, consider Screen Flow."},{"id":84,"category":"Testing","select":1,"question":"During a moderated usability test, what is the main value of asking participants to think aloud?","options":["It replaces observation","It guarantees statistically significant results","It reveals expectations, interpretations, and decision points while they attempt tasks","It teaches participants the correct workflow"],"answers":[2],"explanation":"Think-aloud comments provide insight into the participant's mental model and moments of uncertainty. The moderator should avoid leading or turning the session into training.","tip":"Listen for reasoning while still prioritizing observed behavior over explanations alone."},{"id":85,"category":"Testing","select":1,"question":"When is a focus group more useful than an individual usability test?","options":["When validating server response time","When measuring whether one person can complete a task without help","When checking keyboard focus order","When exploring attitudes, language, and reactions generated through group discussion"],"answers":[3],"explanation":"Focus groups are suited to discussing perceptions, beliefs, and concepts. They are not ideal for measuring individual task performance because group dynamics can influence responses.","tip":"Focus group = discussion and attitudes; usability test = individual behavior while completing tasks."},{"id":86,"category":"Testing","select":1,"question":"A team wants early feedback on the sequence and labels of a new flow before investing in visual polish. Which prototype is most efficient?","options":["A low-fidelity clickable prototype","A performance test script","A final brand campaign","A fully integrated production build"],"answers":[0],"explanation":"Low-fidelity prototypes are fast to create and change, making them appropriate for validating structure, task flow, and terminology before expensive implementation or visual refinement.","tip":"Match prototype fidelity to the question you need to answer. Do not build more than necessary."},{"id":87,"category":"Testing","select":1,"question":"Which participant group gives the strongest evidence for testing a new mobile case workflow?","options":["Any available employees regardless of role","Representative case users who perform the workflow in relevant mobile contexts","Only the executive sponsor","Only members of the design team"],"answers":[1],"explanation":"Participants should reflect the target users' responsibilities, experience levels, devices, environments, and access needs. Convenience samples can miss important barriers.","tip":"Recruit for behavior and context, not merely availability."},{"id":88,"category":"Testing","select":1,"question":"An automated accessibility scan reports no errors. What should the team conclude?","options":["Usability testing is unnecessary","Accessibility testing is complete for every disability","Automated checks should be supplemented with manual keyboard, screen-reader, visual, and user testing","The experience is fully accessible"],"answers":[2],"explanation":"Automated tools detect only certain rule-based issues. Manual inspection and testing with assistive technologies and people with disabilities are necessary to evaluate interaction, meaning, focus behavior, and real usability.","tip":"Automated accessibility testing is valuable but never complete on its own."},{"id":89,"category":"Testing","select":1,"question":"A test produces 25 findings. How should the team prioritize design changes?","options":["Implement only comments from the most senior participant","Fix findings in alphabetical order","Ignore issues that occur before launch","Consider severity, frequency, task impact, accessibility risk, and effort"],"answers":[3],"explanation":"Prioritization should reflect how seriously an issue blocks users, how often it occurs, who is affected, and the consequences for critical tasks and accessibility, balanced with implementation effort.","tip":"Do not treat every observation as equally important; prioritize by user and business impact."},{"id":90,"category":"SLDS","select":1,"question":"A designer needs implementation guidance for a standard component pattern, including anatomy, states, variants, and accessibility notes. Where should the designer look first?","options":["A report subscription","The relevant SLDS component documentation and blueprint","An unrelated custom stylesheet","A database schema diagram"],"answers":[1],"explanation":"SLDS documentation describes supported component patterns, structure, usage, variants, states, and accessibility expectations. Starting there promotes consistency and maintainability.","tip":"Use design-system documentation before inventing a new pattern."},{"id":91,"category":"SLDS","select":1,"question":"A dialog contains Save, Save and New, Cancel, Delete, and Help buttons with identical emphasis. What should the designer do?","options":["Establish a clear action hierarchy with one primary action and appropriate neutral or destructive treatments","Use icons with no accessible names","Remove all button labels","Make every button a brand button"],"answers":[0],"explanation":"Button emphasis should communicate priority and risk. A clear primary action, neutral secondary actions, and an appropriate destructive treatment reduce ambiguity and accidental actions.","tip":"Too many primary buttons eliminate hierarchy. Emphasis should match importance and consequence."},{"id":92,"category":"SLDS","select":1,"question":"A custom component needs standard margin, alignment, and text-treatment adjustments. What should the developer prefer before writing custom CSS?","options":["Inline styles on every element","Selectors targeting internal base-component markup","Supported SLDS utility classes","A duplicate component for each spacing variation"],"answers":[2],"explanation":"SLDS utility classes provide supported, consistent adjustments for common layout, spacing, alignment, and text needs. They reduce custom CSS and help the component stay aligned with the design system.","tip":"Use documented utilities for common adjustments; reserve custom CSS for needs the system does not support."},{"id":93,"category":"SLDS","select":1,"question":"Which SLDS icon category is generally intended for common interface actions such as search, settings, close, or refresh?","options":["Custom object icons","Standard object icons","Utility icons","Doctype icons"],"answers":[2],"explanation":"Utility icons represent common actions and interface concepts. Standard, custom, and doctype icons primarily identify records, object types, or file types.","tip":"Choose icons by semantic purpose, not visual preference. Utility icons usually represent generic UI actions."},{"id":94,"category":"SLDS","select":1,"question":"A status badge uses low-contrast text and color alone to distinguish success from failure. Which revision is best?","options":["Remove the status label","Use sufficient contrast and pair color with clear text or another semantic cue","Animate the badge continuously","Increase saturation only"],"answers":[1],"explanation":"Accessible status communication requires readable contrast and redundant meaning that does not depend solely on color. Clear text also improves comprehension for all users.","tip":"Contrast and non-color cues solve different accessibility problems; use both."},{"id":95,"category":"SLDS","select":1,"question":"When a modal opens, where should keyboard focus generally move?","options":["Into the modal at an appropriate element, while focus remains contained until the modal closes","To the browser address bar","To a random page element","Behind the modal"],"answers":[0],"explanation":"A modal should move focus into its active context, maintain a logical focus sequence within it, support closing by keyboard, and return focus appropriately when dismissed.","tip":"Focus management must follow the user's interaction context, especially for dialogs and overlays."},{"id":96,"category":"SLDS","select":1,"question":"A two-column component should become one column on small screens. Which SLDS capability is designed for this?","options":["Report bucketing","Record ownership rules","Duplicate management","Responsive grid sizing and breakpoint classes"],"answers":[3],"explanation":"The SLDS grid and responsive sizing utilities allow columns to change width or stack at defined viewport ranges while retaining consistent layout behavior.","tip":"Use the grid for responsive structure rather than hardcoded pixel positioning."},{"id":97,"category":"SLDS","select":1,"question":"A component has no data because the user has not created any records yet. What should an effective empty state provide?","options":["A disabled page with no guidance","A technical stack trace","A concise explanation and a relevant next action when one is available","A blank white region"],"answers":[2],"explanation":"An empty state should explain why content is absent and help users move forward, such as creating the first record or adjusting a filter. It should remain concise and relevant.","tip":"Empty states are part of the product experience, not missing design."},{"id":98,"category":"SLDS","select":1,"question":"A form control has visible text nearby, but the text is not programmatically associated with the input. What is the best fix?","options":["Rely on placeholder text only","Use a correctly associated label and connect error or help text with supported accessible markup","Use color to imply the field name","Remove the visible text"],"answers":[1],"explanation":"Programmatic label association enables assistive technology to announce the field's purpose. Supported relationships for help and error text provide necessary context when the field receives focus.","tip":"Visual proximity does not create an accessible name; labels and relationships must exist in the markup."},{"id":99,"category":"SLDS","select":1,"question":"A team needs to customize a supported component's appearance without depending on its internal DOM. Which approach is most appropriate when available?","options":["Use documented styling hooks or supported component variants","Use global !important rules","Copy the rendered HTML into the application","Target undocumented internal classes"],"answers":[0],"explanation":"Supported styling hooks and variants are intended extension points. Internal markup can change between releases, so selectors that depend on it are fragile and can break accessibility or visual consistency.","tip":"Customize through public contracts, not implementation details."},{"id":100,"category":"SLDS","select":1,"question":"Several product teams propose new versions of the same pattern. What design-system governance practice best prevents fragmentation?","options":["Freeze the system so no improvement is possible","Remove all documentation","Allow every team to publish an unrelated version","Define contribution criteria, review proposals, document decisions, and maintain a shared canonical pattern"],"answers":[3],"explanation":"Governance provides a transparent process for evaluating needs, consolidating duplicates, documenting rationale, and evolving shared patterns without losing consistency.","tip":"A healthy design system balances consistency with a governed path for change."}]};
